/**
 * Expected body JSON:
 * {
 *   "mushroomprocess_product_id": "PROD-....",
 *   "storage_location_name": "Location Name"
 * }
 */
const body = $json.body || $json;
const mushroomprocess_product_id = body.mushroomprocess_product_id || body.product_id || null;
const storage_location = body.storage_location_name || body.storage_location || null;

if (!mushroomprocess_product_id) {
  throw new Error('Missing mushroomprocess_product_id');
}

if (!storage_location) {
  throw new Error('Missing storage_location_name');
}

return [{ json: { mushroomprocess_product_id, storage_location } }];

const row = $json || {};
if (row.ok !== true) {
  const error = row.error || 'product_update_failed';
  const details = [
    row.mushroomprocess_product_id ? `product_id=${row.mushroomprocess_product_id}` : null,
    row.requested_storage_location ? `requested_storage_location=${row.requested_storage_location}` : null,
    row.airtable_record_id ? `airtable_record_id=${row.airtable_record_id}` : null
  ].filter(Boolean).join(', ');
  throw new Error(`Postgres product update failed: ${error}${details ? ' (' + details + ')' : ''}`);
}
return [{ json: row }];
